const body = $json.body;
const callback = body.callback_query;
const message = callback.message;
const chatId = message.chat.id;
const messageId = message.message_id;
const from = callback.from;
const username = from.username || null;
const firstName = from.first_name || '';
const lastName = from.last_name || '';
const isPremium = from.is_premium || false;
const languageCode = from.language_code || 'en';
const callbackData = callback.data || '';
const businessConnectionId = message.business_connection_id || null;

const parts = callbackData.split('|');
const action = parts[0];
const query = parts[1] || '';
const offsetRaw = parts[2] || '0';
const offset = parseInt(offsetRaw, 10);

if (action !== 'dzmore') {
  throw new Error('Invalid callback data for dzmore_results');
}

return [{
  json: {
    chat_id: chatId,
    message_id: messageId,
    username: username,
    first_name: firstName,
    last_name: lastName,
    is_premium: isPremium,
    language_code: languageCode,
    callback_data: callbackData,
    query: query,
    offset: offset,
    business_connection_id: businessConnectionId
  }
}];

const deezerData = $input.first().json;
const tracks = deezerData.data || [];
const total = deezerData.total || 0;

if (!tracks || tracks.length === 0) {
  const chatId = $('Parse dzmore callback').item.json.chat_id;
  const replyToMessageId = $('Parse dzmore callback').item.json.message_id;
  const query = $('Parse dzmore callback').item.json.query;

  return [{
    json: {
      chat_id: chatId,
      reply_to_message_id: replyToMessageId,
      text: `❌ Nothing found: <b>${query}</b>\n\n💡 Try:\n• Artist name only\n• Song title only\n• Different spelling`,
      parse_mode: 'HTML',
      send_as_text: true 
    }
  }];
}

const chatId = $('Parse dzmore callback').item.json.chat_id;
const replyToMessageId = $('Parse dzmore callback').item.json.message_id;
const query = $('Parse dzmore callback').item.json.query;
const offset = $('Parse dzmore callback').item.json.offset;

const photo = tracks[0]?.album?.cover_big
  || tracks[0]?.album?.cover_medium
  || '';

const inline_keyboard = tracks.map(track => ([
  {
    text: `🎵 ${track.title} — ${track.artist.name}`,
    callback_data: `dz|${track.id}`
  }
]));

if (offset + tracks.length < total) {
  let moreText = 'More…';

  if (tracks.length >= 5) {
    moreText = `More… (${offset + tracks.length}/${total})`;
  }

  inline_keyboard.push([
    {
      text: moreText,
      callback_data: `dzmore|${query}|${offset + tracks.length}`
    }
  ]);
}

return [{
  json: {
    chat_id: chatId,
    reply_to_message_id: replyToMessageId,
    photo: photo,
    caption: `🔍 Результаты по запросу: <b>${query}</b>`,
    parse_mode: 'HTML',
    reply_markup: { inline_keyboard }
  }
}];

const callbackData = $('Parse dzmore callback').item.json.callback_data;
const parts = callbackData.split('|');
let query = parts[1] || '';

query = query
  .replace(/[^\w\s\u0400-\u04FF-]/gi, ' ')
  .replace(/\s+/g, ' ')
  .trim();

const offset = parts[2] || '0';

return [{
  json: {
    query: query,
    offset: Number(offset)
  }
}];
